223→func (sa *SqliteArchive) Exists(job *schema.Job) bool {
224→	var count int
225→	err := sa.db.QueryRow("SELECT COUNT(*) FROM jobs WHERE job_id = ? AND cluster = ? AND start_time = ?",
226→		job.JobID, job.Cluster, job.StartTime).Scan(&count)
227→	return err == nil && count > 0
228→}
