230→func (sa *SqliteArchive) LoadJobMeta(job *schema.Job) (*schema.Job, error) {
231→	var metaBlob []byte
232→	err := sa.db.QueryRow("SELECT meta_json FROM jobs WHERE job_id = ? AND cluster = ? AND start_time = ?",
233→		job.JobID, job.Cluster, job.StartTime).Scan(&metaBlob)
234→	if err != nil {
235→		cclog.Errorf("SqliteArchive LoadJobMeta() > query error: %v", err)
236→		return nil, err
237→	}
238→
239→	if config.Keys.Validate {
240→		if err := schema.Validate(schema.Meta, bytes.NewReader(metaBlob)); err != nil {
241→			return nil, fmt.Errorf("validate job meta: %v", err)
242→		}
243→	}
244→
245→	return DecodeJobMeta(bytes.NewReader(metaBlob))
246→}
