248→func (sa *SqliteArchive) LoadJobData(job *schema.Job) (schema.JobData, error) {
249→	var dataBlob []byte
250→	var compressed bool
251→	err := sa.db.QueryRow("SELECT data_json, data_compressed FROM jobs WHERE job_id = ? AND cluster = ? AND start_time = ?",
252→		job.JobID, job.Cluster, job.StartTime).Scan(&dataBlob, &compressed)
253→	if err != nil {
254→		cclog.Errorf("SqliteArchive LoadJobData() > query error: %v", err)
255→		return nil, err
256→	}
257→	key := fmt.Sprintf("%s:%d:%d", job.Cluster, job.JobID, job.StartTime)
258→
259→	var reader io.Reader = bytes.NewReader(dataBlob)
260→	if compressed {
261→		gzipReader, err := gzip.NewReader(reader)
262→		if err != nil {
263→			cclog.Errorf("SqliteArchive LoadJobData() > gzip error: %v", err)
264→			return nil, err
265→		}
266→		defer gzipReader.Close()
267→		reader = gzipReader
268→	}
269→
270→	if config.Keys.Validate {
271→		data, _ := io.ReadAll(reader)
272→		if err := schema.Validate(schema.Data, bytes.NewReader(data)); err != nil {
273→			return schema.JobData{}, fmt.Errorf("validate job data: %v", err)
274→		}
275→		return DecodeJobData(bytes.NewReader(data), key)
276→	}
277→
278→	return DecodeJobData(reader, key)
279→}
