332→func (sa *SqliteArchive) StoreJobMeta(job *schema.Job) error {
333→	var metaBuf bytes.Buffer
334→	if err := EncodeJobMeta(&metaBuf, job); err != nil {
335→		cclog.Error("SqliteArchive StoreJobMeta() > encoding error")
336→		return err
337→	}
338→
339→	now := time.Now().Unix()
340→	_, err := sa.db.Exec(`
341→		INSERT INTO jobs (job_id, cluster, start_time, meta_json, created_at, updated_at)
342→		VALUES (?, ?, ?, ?, ?, ?)
343→		ON CONFLICT(job_id, cluster, start_time) DO UPDATE SET
344→			meta_json = excluded.meta_json,
345→			updated_at = excluded.updated_at
346→	`, job.JobID, job.Cluster, job.StartTime, metaBuf.Bytes(), now, now)
347→	if err != nil {
348→		cclog.Errorf("SqliteArchive StoreJobMeta() > insert error: %v", err)
349→		return err
350→	}
351→
352→	return nil
353→}
354→
355→func (sa *SqliteArchive) ImportJob(jobMeta *schema.Job, jobData *schema.JobData) error {
356→	var metaBuf, dataBuf bytes.Buffer
357→	if err := EncodeJobMeta(&metaBuf, jobMeta); err != nil {
358→		cclog.Error("SqliteArchive ImportJob() > encoding meta error")
359→		return err
360→	}
361→	if err := EncodeJobData(&dataBuf, jobData); err != nil {
362→		cclog.Error("SqliteArchive ImportJob() > encoding data error")
363→		return err
364→	}
365→
366→	var dataBytes []byte
367→	var compressed bool
368→
369→	if dataBuf.Len() > 2000 {
370→		var compressedBuf bytes.Buffer
371→		gzipWriter := gzip.NewWriter(&compressedBuf)
372→		if _, err := gzipWriter.Write(dataBuf.Bytes()); err != nil {
373→			cclog.Errorf("SqliteArchive ImportJob() > gzip write error: %v", err)
374→			return err
375→		}
376→		if err := gzipWriter.Close(); err != nil {
377→			cclog.Errorf("SqliteArchive ImportJob() > gzip close error: %v", err)
378→			return err
379→		}
380→		dataBytes = compressedBuf.Bytes()
381→		compressed = true
382→	} else {
383→		dataBytes = dataBuf.Bytes()
384→		compressed = false
385→	}
386→
387→	now := time.Now().Unix()
388→	_, err := sa.db.Exec(`
389→		INSERT INTO jobs (job_id, cluster, start_time, meta_json, data_json, data_compressed, created_at, updated_at)
390→		VALUES (?, ?, ?, ?, ?, ?, ?, ?)
391→		ON CONFLICT(job_id, cluster, start_time) DO UPDATE SET
392→			meta_json = excluded.meta_json,
393→			data_json = excluded.data_json,
394→			data_compressed = excluded.data_compressed,
395→			updated_at = excluded.updated_at
396→	`, jobMeta.JobID, jobMeta.Cluster, jobMeta.StartTime, metaBuf.Bytes(), dataBytes, compressed, now, now)
397→	if err != nil {
398→		cclog.Errorf("SqliteArchive ImportJob() > insert error: %v", err)
399→		return err
400→	}
401→
402→	return nil
403→}
