468→func (sa *SqliteArchive) Compress(jobs []*schema.Job) {
469→	var cnt int
470→	start := time.Now()
471→
472→	tx, err := sa.db.Begin()
473→	if err != nil {
474→		cclog.Errorf("SqliteArchive Compress() > transaction error: %v", err)
475→		return
476→	}
477→	defer tx.Rollback()
478→
479→	stmt, err := tx.Prepare("UPDATE jobs SET data_json = ?, data_compressed = 1 WHERE job_id = ? AND cluster = ? AND start_time = ?")
480→	if err != nil {
481→		cclog.Errorf("SqliteArchive Compress() > prepare error: %v", err)
482→		return
483→	}
484→	defer stmt.Close()
485→
486→	for _, job := range jobs {
487→		var dataBlob []byte
488→		var compressed bool
489→		err := sa.db.QueryRow("SELECT data_json, data_compressed FROM jobs WHERE job_id = ? AND cluster = ? AND start_time = ?",
490→			job.JobID, job.Cluster, job.StartTime).Scan(&dataBlob, &compressed)
491→		if err != nil || compressed || len(dataBlob) < 2000 {
492→			continue // Skip if error, already compressed, or too small
493→		}
494→
495→		// Compress the data
496→		var compressedBuf bytes.Buffer
497→		gzipWriter := gzip.NewWriter(&compressedBuf)
498→		if _, err := gzipWriter.Write(dataBlob); err != nil {
499→			cclog.Errorf("SqliteArchive Compress() > gzip error: %v", err)
500→			gzipWriter.Close()
501→			continue
502→		}
503→		gzipWriter.Close()
504→
505→		if _, err := stmt.Exec(compressedBuf.Bytes(), job.JobID, job.Cluster, job.StartTime); err != nil {
506→			cclog.Errorf("SqliteArchive Compress() > update error: %v", err)
507→		} else {
508→			cnt++
509→		}
510→	}
511→
512→	if err := tx.Commit(); err != nil {
513→		cclog.Errorf("SqliteArchive Compress() > commit error: %v", err)
514→		return
515→	}
516→
517→	cclog.Infof("Compression Service - %d jobs in SQLite took %s", cnt, time.Since(start))
518→}
