552→type sqliteJobRow struct {
553→	metaBlob   []byte
554→	dataBlob   []byte
555→	compressed bool
556→}
557→
558→func (sa *SqliteArchive) Iter(loadMetricData bool) <-chan JobContainer {
559→	ch := make(chan JobContainer)
560→
561→	go func() {
562→		defer close(ch)
563→
564→		const chunkSize = 1000
565→		offset := 0
566→
567→		var query string
568→		if loadMetricData {
569→			query = "SELECT meta_json, data_json, data_compressed FROM jobs ORDER BY cluster, start_time LIMIT ? OFFSET ?"
570→		} else {
571→			query = "SELECT meta_json FROM jobs ORDER BY cluster, start_time LIMIT ? OFFSET ?"
572→		}
573→
574→		numWorkers := 4
575→		jobRows := make(chan sqliteJobRow, numWorkers*2)
576→		var wg sync.WaitGroup
577→
578→		for range numWorkers {
579→			wg.Go(func() {
580→				for row := range jobRows {
581→					job, err := DecodeJobMeta(bytes.NewReader(row.metaBlob))
582→					if err != nil {
583→						cclog.Errorf("SqliteArchive Iter() > decode meta error: %v", err)
584→						continue
585→					}
586→
587→					if loadMetricData && row.dataBlob != nil {
588→						var reader io.Reader = bytes.NewReader(row.dataBlob)
589→						if row.compressed {
590→							gzipReader, err := gzip.NewReader(reader)
591→							if err != nil {
592→								cclog.Errorf("SqliteArchive Iter() > gzip error: %v", err)
593→								ch <- JobContainer{Meta: job, Data: nil}
594→								continue
595→							}
596→							decompressed, err := io.ReadAll(gzipReader)
597→							gzipReader.Close()
598→							if err != nil {
599→								cclog.Errorf("SqliteArchive Iter() > decompress error: %v", err)
600→								ch <- JobContainer{Meta: job, Data: nil}
601→								continue
602→							}
603→							reader = bytes.NewReader(decompressed)
604→						}
605→
606→						key := fmt.Sprintf("%s:%d:%d", job.Cluster, job.JobID, job.StartTime)
607→						jobData, err := DecodeJobData(reader, key)
608→						if err != nil {
609→							cclog.Errorf("SqliteArchive Iter() > decode data error: %v", err)
610→							ch <- JobContainer{Meta: job, Data: nil}
611→						} else {
612→							ch <- JobContainer{Meta: job, Data: &jobData}
613→						}
614→					} else {
615→						ch <- JobContainer{Meta: job, Data: nil}
616→					}
617→				}
618→			})
619→		}
620→
621→		for {
622→			rows, err := sa.db.Query(query, chunkSize, offset)
623→			if err != nil {
624→				cclog.Fatalf("SqliteArchive Iter() > query error: %s", err.Error())
625→			}
626→
627→			rowCount := 0
628→			for rows.Next() {
629→				var row sqliteJobRow
630→
631→				if loadMetricData {
632→					if err := rows.Scan(&row.metaBlob, &row.dataBlob, &row.compressed); err != nil {
633→						cclog.Errorf("SqliteArchive Iter() > scan error: %v", err)
634→						continue
635→					}
636→				} else {
637→					if err := rows.Scan(&row.metaBlob); err != nil {
638→						cclog.Errorf("SqliteArchive Iter() > scan error: %v", err)
639→						continue
640→					}
641→					row.dataBlob = nil
642→					row.compressed = false
643→				}
644→
645→				jobRows <- row
646→				rowCount++
647→			}
648→			rows.Close()
649→
650→			if rowCount < chunkSize {
651→				break
652→			}
653→
654→			offset += chunkSize
655→		}
656→
657→		close(jobRows)
658→		wg.Wait()
659→	}()
660→
661→	return ch
662→}
663→
664→func (sa *SqliteArchive) StoreClusterCfg(name string, config *schema.Cluster) error {
665→	var configBuf bytes.Buffer
666→	if err := EncodeCluster(&configBuf, config); err != nil {
667→		cclog.Error("SqliteArchive StoreClusterCfg() > encoding error")
668→		return err
669→	}
670→
671→	now := time.Now().Unix()
672→	_, err := sa.db.Exec(`
673→		INSERT INTO clusters (name, config_json, updated_at)
674→		VALUES (?, ?, ?)
675→		ON CONFLICT(name) DO UPDATE SET
676→			config_json = excluded.config_json,
677→			updated_at = excluded.updated_at
678→	`, name, configBuf.Bytes(), now)
679→	if err != nil {
680→		cclog.Errorf("SqliteArchive StoreClusterCfg() > insert error: %v", err)
681→		return err
682→	}
683→
684→	// Update clusters list if new
685→	found := slices.Contains(sa.clusters, name)
686→	if !found {
687→		sa.clusters = append(sa.clusters, name)
688→	}
689→
690→	return nil
691→}
