120→// AddUser creates a new user in the database.
121→// Passwords are automatically hashed with bcrypt before storage.
122→// Auth source determines authentication method (local, LDAP, etc.).
123→//
124→// Required fields: Username, Roles
125→// Optional fields: Name, Email, Password, Projects, AuthSource
126→func (r *UserRepository) AddUser(user *schema.User) error {
127→	rolesJson, _ := json.Marshal(user.Roles)
128→	projectsJson, _ := json.Marshal(user.Projects)
129→
130→	cols := []string{"username", "roles", "projects"}
131→	vals := []any{user.Username, string(rolesJson), string(projectsJson)}
132→
133→	if user.Name != "" {
134→		cols = append(cols, "name")
135→		vals = append(vals, user.Name)
136→	}
137→	if user.Email != "" {
138→		cols = append(cols, "email")
139→		vals = append(vals, user.Email)
140→	}
141→	if user.Password != "" {
142→		password, err := bcrypt.GenerateFromPassword([]byte(user.Password), bcrypt.DefaultCost)
143→		if err != nil {
144→			cclog.Error("Error while encrypting new user password")
145→			return err
146→		}
147→		cols = append(cols, "password")
148→		vals = append(vals, string(password))
149→	}
150→	if user.AuthSource != -1 {
151→		cols = append(cols, "ldap")
152→		vals = append(vals, int(user.AuthSource))
153→	}
154→
155→	if _, err := sq.Insert("hpc_user").Columns(cols...).Values(vals...).RunWith(r.DB).Exec(); err != nil {
156→		cclog.Errorf("Error while inserting new user '%v' into DB", user.Username)
157→		return err
158→	}
159→
160→	cclog.Infof("new user %#v created (roles: %s, auth-source: %d, projects: %s)", user.Username, rolesJson, user.AuthSource, projectsJson)
161→
162→	// DEPRECATED: SUPERSEDED BY NEW USER CONFIG - userConfig.go / web.go
163→	defaultMetricsCfg, err := config.LoadDefaultMetricsConfig()
164→	if err != nil {
165→		cclog.Errorf("Error loading default metrics config: %v", err)
166→	} else if defaultMetricsCfg != nil {
167→		for _, cluster := range defaultMetricsCfg.Clusters {
168→			metricsArray := config.ParseMetricsString(cluster.DefaultMetrics)
169→			metricsJSON, err := json.Marshal(metricsArray)
170→			if err != nil {
171→				cclog.Errorf("Error marshaling default metrics for cluster %s: %v", cluster.Name, err)
172→				continue
173→			}
174→			// Note: StatisticsTable now has different key (metricConfig_jobViewTableMetrics): Not updated here.
175→			confKey := "metricConfig_jobViewPlotMetrics:" + cluster.Name
176→			if _, err := sq.Insert("configuration").
177→				Columns("username", "confkey", "value").
178→				Values(user.Username, confKey, string(metricsJSON)).
179→				RunWith(r.DB).Exec(); err != nil {
180→				cclog.Errorf("Error inserting default job view metrics for user %s and cluster %s: %v", user.Username, cluster.Name, err)
181→			} else {
182→				cclog.Infof("Default job view metrics for user %s and cluster %s set to %s", user.Username, cluster.Name, string(metricsJSON))
183→			}
184→		}
185→	}
186→	// END DEPRECATION
187→
188→	return nil
189→}
