191→// AddUserIfNotExists inserts a user only if the username does not already exist.
192→// Uses INSERT OR IGNORE to avoid UNIQUE constraint errors when a user is
193→// concurrently created (e.g., by a login while LDAP sync is running).
194→// Unlike AddUser, this intentionally skips the deprecated default metrics config insertion.
195→func (r *UserRepository) AddUserIfNotExists(user *schema.User) error {
196→	rolesJson, _ := json.Marshal(user.Roles)
197→	projectsJson, _ := json.Marshal(user.Projects)
198→
199→	cols := "username, name, roles, projects, ldap"
200→	_, err := r.DB.Exec(
201→		`INSERT OR IGNORE INTO hpc_user (`+cols+`) VALUES (?, ?, ?, ?, ?)`,
202→		user.Username, user.Name, string(rolesJson), string(projectsJson), int(user.AuthSource))
203→	return err
204→}
