206→func (r *UserRepository) UpdateUser(dbUser *schema.User, user *schema.User) error {
207→	// user contains updated info -> Apply to dbUser
208→	// --- Simple Name Update ---
209→	if dbUser.Name != user.Name {
210→		if _, err := sq.Update("hpc_user").Set("name", user.Name).Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec(); err != nil {
211→			cclog.Errorf("error while updating name of user '%s'", user.Username)
212→			return err
213→		}
214→	}
215→
216→	// --- Def Helpers ---
217→	// Helper to update roles
218→	updateRoles := func(roles []string) error {
219→		rolesJSON, _ := json.Marshal(roles)
220→		_, err := sq.Update("hpc_user").Set("roles", rolesJSON).Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec()
221→		return err
222→	}
223→
224→	// Helper to update projects
225→	updateProjects := func(projects []string) error {
226→		projectsJSON, _ := json.Marshal(projects)
227→		_, err := sq.Update("hpc_user").Set("projects", projectsJSON).Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec()
228→		return err
229→	}
230→
231→	// Helper to clear projects
232→	clearProjects := func() error {
233→		_, err := sq.Update("hpc_user").Set("projects", "[]").Where("hpc_user.username = ?", dbUser.Username).RunWith(r.DB).Exec()
234→		return err
235→	}
236→
237→	// --- Manager Role Handling ---
238→	if dbUser.HasRole(schema.RoleManager) && user.HasRole(schema.RoleManager) && !reflect.DeepEqual(dbUser.Projects, user.Projects) {
239→		// Existing Manager: update projects
240→		if err := updateProjects(user.Projects); err != nil {
241→			return err
242→		}
243→	} else if dbUser.HasRole(schema.RoleUser) && user.HasRole(schema.RoleManager) && user.HasNotRoles([]schema.Role{schema.RoleAdmin}) {
244→		// New Manager: update roles and projects
245→		if err := updateRoles(user.Roles); err != nil {
246→			return err
247→		}
248→		if err := updateProjects(user.Projects); err != nil {
249→			return err
250→		}
251→	} else if dbUser.HasRole(schema.RoleManager) && user.HasNotRoles([]schema.Role{schema.RoleAdmin, schema.RoleManager}) {
252→		// Remove Manager: update roles and clear projects
253→		if err := updateRoles(user.Roles); err != nil {
254→			return err
255→		}
256→		if err := clearProjects(); err != nil {
257→			return err
258→		}
259→	}
260→
261→	// --- Support Role Handling ---
262→	if dbUser.HasRole(schema.RoleUser) && dbUser.HasNotRoles([]schema.Role{schema.RoleSupport}) &&
263→		user.HasRole(schema.RoleSupport) && user.HasNotRoles([]schema.Role{schema.RoleAdmin}) {
264→		// New Support: update roles
265→		if err := updateRoles(user.Roles); err != nil {
266→			return err
267→		}
268→	} else if dbUser.HasRole(schema.RoleSupport) && user.HasNotRoles([]schema.Role{schema.RoleAdmin, schema.RoleSupport}) {
269→		// Remove Support: update roles
270→		if err := updateRoles(user.Roles); err != nil {
271→			return err
272→		}
273→	}
274→
275→	return nil
276→}
