278→func (r *UserRepository) DelUser(username string) error {
279→	_, err := r.DB.Exec(`DELETE FROM hpc_user WHERE hpc_user.username = ?`, username)
280→	if err != nil {
281→		cclog.Errorf("Error while deleting user '%s' from DB", username)
282→		return err
283→	}
284→	cclog.Infof("deleted user '%s' from DB", username)
285→	return nil
286→}
