288→func (r *UserRepository) ListUsers(specialsOnly bool) ([]*schema.User, error) {
289→	q := sq.Select("username", "name", "email", "roles", "projects").From("hpc_user")
290→	if specialsOnly {
291→		q = q.Where("(roles != '[\"user\"]' AND roles != '[]')")
292→	}
293→
294→	rows, err := q.RunWith(r.DB).Query()
295→	if err != nil {
296→		cclog.Warn("Error while querying user list")
297→		return nil, err
298→	}
299→
300→	users := make([]*schema.User, 0)
301→	defer rows.Close()
302→	for rows.Next() {
303→		rawroles := ""
304→		rawprojects := ""
305→		user := &schema.User{}
306→		var name, email sql.NullString
307→		if err := rows.Scan(&user.Username, &name, &email, &rawroles, &rawprojects); err != nil {
308→			cclog.Warn("Error while scanning user list")
309→			return nil, err
310→		}
311→
312→		if err := json.Unmarshal([]byte(rawroles), &user.Roles); err != nil {
313→			cclog.Warn("Error while unmarshaling raw role list")
314→			return nil, err
315→		}
316→
317→		if err := json.Unmarshal([]byte(rawprojects), &user.Projects); err != nil {
318→			return nil, err
319→		}
320→
321→		user.Name = name.String
322→		user.Email = email.String
323→		users = append(users, user)
324→	}
325→	return users, nil
326→}
