328→// AddRole adds a role to a user's role list.
329→// Role string is automatically lowercased.
330→// Valid roles: admin, support, manager, api, user
331→//
332→// Returns error if:
333→//   - User doesn't exist
334→//   - Role is invalid
335→//   - User already has the role
336→func (r *UserRepository) AddRole(
337→	ctx context.Context,
338→	username string,
339→	queryrole string,
340→) error {
341→	newRole := strings.ToLower(queryrole)
342→	user, err := r.GetUser(username)
343→	if err != nil {
344→		cclog.Warnf("Could not load user '%s'", username)
345→		return err
346→	}
347→
348→	exists, valid := user.HasValidRole(newRole)
349→
350→	if !valid {
351→		return fmt.Errorf("supplied role is no valid option : %v", newRole)
352→	}
353→	if exists {
354→		return fmt.Errorf("user %v already has role %v", username, newRole)
355→	}
356→
357→	roles, _ := json.Marshal(append(user.Roles, newRole))
358→	if _, err := sq.Update("hpc_user").Set("roles", roles).Where("hpc_user.username = ?", username).RunWith(r.DB).Exec(); err != nil {
359→		cclog.Errorf("error while adding new role for user '%s'", user.Username)
360→		return err
361→	}
362→	return nil
363→}
364→
365→// RemoveRole removes a role from a user's role list.
366→//
367→// Special rules:
368→//   - Cannot remove "manager" role while user has assigned projects
369→//   - Must remove all projects first before removing manager role
370→func (r *UserRepository) RemoveRole(ctx context.Context, username string, queryrole string) error {
371→	oldRole := strings.ToLower(queryrole)
372→	user, err := r.GetUser(username)
373→	if err != nil {
374→		cclog.Warnf("Could not load user '%s'", username)
375→		return err
376→	}
377→
378→	exists, valid := user.HasValidRole(oldRole)
379→
380→	if !valid {
381→		return fmt.Errorf("supplied role is no valid option : %v", oldRole)
382→	}
383→	if !exists {
384→		return fmt.Errorf("role already deleted for user '%v': %v", username, oldRole)
385→	}
386→
387→	if oldRole == schema.GetRoleString(schema.RoleManager) && len(user.Projects) != 0 {
388→		return fmt.Errorf("cannot remove role 'manager' while user %s still has assigned project(s) : %v", username, user.Projects)
389→	}
390→
391→	var newroles []string
392→	for _, r := range user.Roles {
393→		if r != oldRole {
394→			newroles = append(newroles, r) // Append all roles not matching requested to be deleted role
395→		}
396→	}
397→
398→	mroles, _ := json.Marshal(newroles)
399→	if _, err := sq.Update("hpc_user").Set("roles", mroles).Where("hpc_user.username = ?", username).RunWith(r.DB).Exec(); err != nil {
400→		cclog.Errorf("Error while removing role for user '%s'", user.Username)
401→		return err
402→	}
403→	return nil
404→}
405→
406→// AddProject assigns a project to a manager user.
407→// Only users with the "manager" role can have assigned projects.
408→//
409→// Returns error if:
410→//   - User doesn't have manager role
411→//   - User already manages the project
412→func (r *UserRepository) AddProject(
413→	ctx context.Context,
414→	username string,
415→	project string,
416→) error {
417→	user, err := r.GetUser(username)
418→	if err != nil {
419→		return err
420→	}
421→
422→	if !user.HasRole(schema.RoleManager) {
423→		return fmt.Errorf("user '%s' is not a manager", username)
424→	}
425→
426→	if user.HasProject(project) {
427→		return fmt.Errorf("user '%s' already manages project '%s'", username, project)
428→	}
429→
430→	projects, _ := json.Marshal(append(user.Projects, project))
431→	if _, err := sq.Update("hpc_user").Set("projects", projects).Where("hpc_user.username = ?", username).RunWith(r.DB).Exec(); err != nil {
432→		return err
433→	}
434→
435→	return nil
436→}
437→
438→func (r *UserRepository) RemoveProject(ctx context.Context, username string, project string) error {
439→	user, err := r.GetUser(username)
440→	if err != nil {
441→		return err
442→	}
443→
444→	if !user.HasRole(schema.RoleManager) {
445→		return fmt.Errorf("user '%#v' is not a manager", username)
446→	}
447→
448→	if !user.HasProject(project) {
449→		return fmt.Errorf("user '%#v': Cannot remove project '%#v' - Does not match", username, project)
450→	}
451→
452→	var exists bool
453→	var newprojects []string
454→	for _, p := range user.Projects {
455→		if p != project {
456→			newprojects = append(newprojects, p) // Append all projects not matching requested to be deleted project
457→		} else {
458→			exists = true
459→		}
460→	}
461→
462→	if exists {
463→		var result any
464→		if len(newprojects) == 0 {
465→			result = "[]"
466→		} else {
467→			result, _ = json.Marshal(newprojects)
468→		}
469→		if _, err := sq.Update("hpc_user").Set("projects", result).Where("hpc_user.username = ?", username).RunWith(r.DB).Exec(); err != nil {
470→			return err
471→		}
472→		return nil
473→	} else {
474→		return fmt.Errorf("user %s already does not manage project %s", username, project)
475→	}
476→}
477→
478→type ContextKey string
479→
480→const ContextUserKey ContextKey = "user"
481→
482→func GetUserFromContext(ctx context.Context) *schema.User {
483→	x := ctx.Value(ContextUserKey)
484→	if x == nil {
485→		cclog.Warnf("no user retrieved from context")
486→		return nil
487→	}
488→	// cclog.Infof("user retrieved from context: %v", x.(*schema.User))
489→	return x.(*schema.User)
490→}
491→
492→func (r *UserRepository) FetchUserInCtx(ctx context.Context, username string) (*model.User, error) {
493→	me := GetUserFromContext(ctx)
494→	if me != nil && me.Username != username &&
495→		me.HasNotRoles([]schema.Role{schema.RoleAdmin, schema.RoleSupport, schema.RoleManager}) {
496→		return nil, errors.New("forbidden")
497→	}
498→
499→	user := &model.User{Username: username}
500→	var name, email sql.NullString
501→	if err := sq.Select("name", "email").From("hpc_user").Where("hpc_user.username = ?", username).
502→		RunWith(r.DB).QueryRow().Scan(&name, &email); err != nil {
503→		if err == sql.ErrNoRows {
504→			/* This warning will be logged *often* for non-local users, i.e. users mentioned only in job-table or archive, */
505→			/* since FetchUser will be called to retrieve full name and mail for every job in query/list									 */
506→			// cclog.Warnf("User '%s' Not found in DB", username)
507→			return nil, nil
508→		}
509→
510→		cclog.Warnf("Error while fetching user '%s'", username)
511→		return nil, err
512→	}
513→
514→	user.Name = name.String
515→	user.Email = email.String
516→	return user, nil
517→}
