  5→package repository
  6→
  7→import (
  8→	"fmt"
  9→
 10→	"github.com/jmoiron/sqlx"
 11→)
 12→
 13→// Transaction wraps a database transaction for job-related operations.
 14→type Transaction struct {
 15→	tx *sqlx.Tx
 16→}
 17→
 18→// TransactionInit begins a new transaction.
 19→func (r *JobRepository) TransactionInit() (*Transaction, error) {
 20→	tx, err := r.DB.Beginx()
 21→	if err != nil {
 22→		return nil, fmt.Errorf("beginning transaction: %w", err)
 23→	}
 24→	return &Transaction{tx: tx}, nil
 25→}
 26→
 27→// Commit commits the transaction.
 28→// After calling Commit, the transaction should not be used again.
 29→func (t *Transaction) Commit() error {
 30→	if t.tx == nil {
 31→		return fmt.Errorf("transaction already committed or rolled back")
 32→	}
 33→	err := t.tx.Commit()
 34→	t.tx = nil // Mark as completed
 35→	if err != nil {
 36→		return fmt.Errorf("committing transaction: %w", err)
 37→	}
 38→	return nil
 39→}
 40→
 41→// Rollback rolls back the transaction.
 42→// It's safe to call Rollback on an already committed or rolled back transaction.
 43→func (t *Transaction) Rollback() error {
 44→	if t.tx == nil {
 45→		return nil // Already committed/rolled back
 46→	}
 47→	err := t.tx.Rollback()
 48→	t.tx = nil // Mark as completed
 49→	if err != nil {
 50→		return fmt.Errorf("rolling back transaction: %w", err)
 51→	}
 52→	return nil
 53→}
 54→
 55→// TransactionEnd commits the transaction.
 56→// Deprecated: Use Commit() instead.
 57→func (r *JobRepository) TransactionEnd(t *Transaction) error {
 58→	return t.Commit()
 59→}
 60→
 61→// TransactionAddNamed executes a named query within the transaction.
 62→func (r *JobRepository) TransactionAddNamed(
 63→	t *Transaction,
 64→	query string,
 65→	args ...any,
 66→) (int64, error) {
 67→	if t.tx == nil {
 68→		return 0, fmt.Errorf("transaction is nil or already completed")
 69→	}
 70→
 71→	res, err := t.tx.NamedExec(query, args)
 72→	if err != nil {
 73→		return 0, fmt.Errorf("named exec: %w", err)
 74→	}
 75→
 76→	id, err := res.LastInsertId()
 77→	if err != nil {
 78→		return 0, fmt.Errorf("getting last insert id: %w", err)
 79→	}
 80→
 81→	return id, nil
 82→}
 83→
 84→// TransactionAdd executes a query within the transaction.
 85→func (r *JobRepository) TransactionAdd(t *Transaction, query string, args ...any) (int64, error) {
 86→	if t.tx == nil {
 87→		return 0, fmt.Errorf("transaction is nil or already completed")
 88→	}
 89→
 90→	res, err := t.tx.Exec(query, args...)
 91→	if err != nil {
 92→		return 0, fmt.Errorf("exec: %w", err)
 93→	}
 94→
 95→	id, err := res.LastInsertId()
 96→	if err != nil {
 97→		return 0, fmt.Errorf("getting last insert id: %w", err)
 98→	}
 99→
