 24→// createParquetTarget creates a ParquetTarget (file or S3) from the retention config.
 25→func createParquetTarget(cfg Retention) (pqarchive.ParquetTarget, error) {
 26→	switch cfg.TargetKind {
 27→	case "s3":
 28→		return pqarchive.NewS3Target(pqarchive.S3TargetConfig{
 29→			Endpoint:     cfg.TargetEndpoint,
 30→			Bucket:       cfg.TargetBucket,
 31→			AccessKey:    cfg.TargetAccessKey,
 32→			SecretKey:    cfg.TargetSecretKey,
 33→			Region:       cfg.TargetRegion,
 34→			UsePathStyle: cfg.TargetUsePathStyle,
 35→		})
 36→	default:
 37→		return pqarchive.NewFileTarget(cfg.TargetPath)
 38→	}
 39→}
 40→
 41→// createTargetBackend creates a secondary archive backend (file or S3) for JSON copy/move.
 42→func createTargetBackend(cfg Retention) (archive.ArchiveBackend, error) {
 43→	var raw json.RawMessage
 44→	var err error
 45→
 46→	switch cfg.TargetKind {
 47→	case "s3":
 48→		raw, err = json.Marshal(map[string]any{
 49→			"kind":           "s3",
 50→			"endpoint":       cfg.TargetEndpoint,
 51→			"bucket":         cfg.TargetBucket,
 52→			"access-key":     cfg.TargetAccessKey,
 53→			"secret-key":     cfg.TargetSecretKey,
 54→			"region":         cfg.TargetRegion,
 55→			"use-path-style": cfg.TargetUsePathStyle,
 56→		})
 57→	default:
 58→		raw, err = json.Marshal(map[string]string{
 59→			"kind": "file",
 60→			"path": cfg.TargetPath,
 61→		})
 62→	}
 63→	if err != nil {
 64→		return nil, fmt.Errorf("marshal target config: %w", err)
 65→	}
 66→	return archive.InitBackend(raw)
 67→}
