 69→// transferJobsJSON copies job data from source archive to target backend in JSON format.
 70→func transferJobsJSON(jobs []*schema.Job, src archive.ArchiveBackend, dst archive.ArchiveBackend) error {
 71→	// Transfer cluster configs for all clusters referenced by jobs
 72→	clustersDone := make(map[string]bool)
 73→	for _, job := range jobs {
 74→		if clustersDone[job.Cluster] {
 75→			continue
 76→		}
 77→		clusterCfg, err := src.LoadClusterCfg(job.Cluster)
 78→		if err != nil {
 79→			cclog.Warnf("Retention: load cluster config %q: %v", job.Cluster, err)
 80→		} else {
 81→			if err := dst.StoreClusterCfg(job.Cluster, clusterCfg); err != nil {
 82→				cclog.Warnf("Retention: store cluster config %q: %v", job.Cluster, err)
 83→			}
 84→		}
 85→		clustersDone[job.Cluster] = true
 86→	}
 87→
 88→	for _, job := range jobs {
 89→		meta, err := src.LoadJobMeta(job)
 90→		if err != nil {
 91→			cclog.Warnf("Retention: load meta for job %d: %v", job.JobID, err)
 92→			continue
 93→		}
 94→		data, err := src.LoadJobData(job)
 95→		if err != nil {
 96→			cclog.Warnf("Retention: load data for job %d: %v", job.JobID, err)
 97→			continue
 98→		}
 99→		if err := dst.ImportJob(meta, &data); err != nil {
100→			cclog.Warnf("Retention: import job %d: %v", job.JobID, err)
101→			continue
102→		}
103→	}
104→	return nil
105→}
