151→// cleanupAfterTransfer removes jobs from archive and optionally from DB.
152→func cleanupAfterTransfer(jobs []*schema.Job, startTime int64, includeDB bool, omitTagged string) {
153→	archive.GetHandle().CleanUp(jobs)
154→
155→	if includeDB {
156→		cnt, err := jobRepo.DeleteJobsBefore(startTime, omitTagged)
157→		if err != nil {
158→			cclog.Errorf("Retention: delete jobs from db: %v", err)
159→		} else {
160→			cclog.Infof("Retention: removed %d jobs from db", cnt)
161→		}
162→		if err = jobRepo.Optimize(); err != nil {
163→			cclog.Errorf("Retention: db optimization error: %v", err)
164→		}
165→	}
166→}
