168→// readCopyMarker reads the last-processed timestamp from a copy marker file.
169→func readCopyMarker(cfg Retention) int64 {
170→	var data []byte
171→	var err error
172→
173→	switch cfg.TargetKind {
174→	case "s3":
175→		// For S3 we store the marker locally alongside the config
176→		data, err = os.ReadFile(copyMarkerPath(cfg))
177→	default:
178→		data, err = os.ReadFile(filepath.Join(cfg.TargetPath, ".copy-marker"))
179→	}
180→	if err != nil {
181→		return 0
182→	}
183→	ts, err := strconv.ParseInt(strings.TrimSpace(string(data)), 10, 64)
184→	if err != nil {
185→		return 0
186→	}
187→	return ts
188→}
189→
190→// writeCopyMarker writes the last-processed timestamp to a copy marker file.
191→func writeCopyMarker(cfg Retention, ts int64) {
192→	content := []byte(strconv.FormatInt(ts, 10))
193→	var err error
194→
195→	switch cfg.TargetKind {
196→	case "s3":
197→		err = os.WriteFile(copyMarkerPath(cfg), content, 0o640)
198→	default:
199→		err = os.WriteFile(filepath.Join(cfg.TargetPath, ".copy-marker"), content, 0o640)
200→	}
201→	if err != nil {
202→		cclog.Warnf("Retention: write copy marker: %v", err)
203→	}
204→}
205→
206→func copyMarkerPath(cfg Retention) string {
207→	// For S3 targets, store the marker in a local temp-style path derived from the bucket name
208→	return filepath.Join(os.TempDir(), fmt.Sprintf("cc-copy-marker-%s", cfg.TargetBucket))
209→}
