211→func RegisterRetentionDeleteService(cfg Retention) {
212→	cclog.Info("Register retention delete service")
213→
214→	s.NewJob(gocron.DailyJob(1, gocron.NewAtTimes(gocron.NewAtTime(3, 0, 0))),
215→		gocron.NewTask(
216→			func() {
217→				startTime := time.Now().Unix() - int64(cfg.Age*24*3600)
218→				jobs, err := jobRepo.FindJobsBetween(0, startTime, cfg.OmitTagged)
219→				if err != nil {
220→					cclog.Warnf("Retention delete: error finding jobs: %v", err)
221→					return
222→				}
223→				if len(jobs) == 0 {
224→					return
225→				}
226→
227→				cclog.Infof("Retention delete: processing %d jobs", len(jobs))
228→				cleanupAfterTransfer(jobs, startTime, cfg.IncludeDB, cfg.OmitTagged)
229→			}))
230→}
