232→func RegisterRetentionCopyService(cfg Retention) {
233→	cclog.Infof("Register retention copy service (format=%s, target=%s)", cfg.Format, cfg.TargetKind)
234→
235→	maxFileSizeMB := cfg.MaxFileSizeMB
236→	if maxFileSizeMB <= 0 {
237→		maxFileSizeMB = 512
238→	}
239→
240→	s.NewJob(gocron.DailyJob(1, gocron.NewAtTimes(gocron.NewAtTime(4, 0, 0))),
241→		gocron.NewTask(
242→			func() {
243→				cutoff := time.Now().Unix() - int64(cfg.Age*24*3600)
244→				lastProcessed := readCopyMarker(cfg)
245→
246→				jobs, err := jobRepo.FindJobsBetween(lastProcessed, cutoff, cfg.OmitTagged)
247→				if err != nil {
248→					cclog.Warnf("Retention copy: error finding jobs: %v", err)
249→					return
250→				}
251→				if len(jobs) == 0 {
252→					return
253→				}
254→
255→				cclog.Infof("Retention copy: processing %d jobs", len(jobs))
256→				ar := archive.GetHandle()
257→
258→				switch cfg.Format {
259→				case "parquet":
260→					target, err := createParquetTarget(cfg)
261→					if err != nil {
262→						cclog.Errorf("Retention copy: create parquet target: %v", err)
263→						return
264→					}
265→					if err := transferJobsParquet(jobs, ar, target, maxFileSizeMB); err != nil {
266→						cclog.Errorf("Retention copy: parquet transfer: %v", err)
267→						return
268→					}
269→				default: // json
270→					dst, err := createTargetBackend(cfg)
271→					if err != nil {
272→						cclog.Errorf("Retention copy: create target backend: %v", err)
273→						return
274→					}
275→					if err := transferJobsJSON(jobs, ar, dst); err != nil {
276→						cclog.Errorf("Retention copy: json transfer: %v", err)
277→						return
278→					}
279→				}
280→
281→				writeCopyMarker(cfg, cutoff)
282→			}))
283→}
