 22→// HandleImportFlag imports jobs from file pairs specified in a comma-separated flag string.
 23→//
 24→// The flag format is: "<path-to-meta.json>:<path-to-data.json>[,<path-to-meta2.json>:<path-to-data2.json>,...]"
 25→//
 26→// For each job pair, this function:
 27→//  1. Reads and validates the metadata JSON file (schema.Job)
 28→//  2. Reads and validates the job data JSON file (schema.JobData)
 29→//  3. Enriches the job with calculated footprints and energy metrics
 30→//  4. Validates the job using SanityChecks()
 31→//  5. Imports the job into the archive
 32→//  6. Inserts the job into the database with associated tags
 33→//
 34→// Schema validation is performed if config.Keys.Validate is true.
 35→//
 36→// Returns an error if file reading, validation, enrichment, or database operations fail.
 37→// The function stops processing on the first error encountered.
 38→func HandleImportFlag(flag string) error {
 39→	r := repository.GetJobRepository()
 40→
 41→	for pair := range strings.SplitSeq(flag, ",") {
 42→		files := strings.Split(pair, ":")
 43→		if len(files) != 2 {
 44→			return fmt.Errorf("REPOSITORY/INIT > invalid import flag format")
 45→		}
 46→
 47→		raw, err := os.ReadFile(files[0])
 48→		if err != nil {
 49→			cclog.Warn("Error while reading metadata file for import")
 50→			return err
 51→		}
 52→
 53→		if config.Keys.Validate {
 54→			if err = schema.Validate(schema.Meta, bytes.NewReader(raw)); err != nil {
 55→				return fmt.Errorf("REPOSITORY/INIT > validate job meta: %v", err)
 56→			}
 57→		}
 58→		dec := json.NewDecoder(bytes.NewReader(raw))
 59→		dec.DisallowUnknownFields()
 60→		job := schema.Job{
 61→			Shared:           "none",
 62→			MonitoringStatus: schema.MonitoringStatusRunningOrArchiving,
 63→		}
 64→		if err = dec.Decode(&job); err != nil {
 65→			cclog.Warn("Error while decoding raw json metadata for import")
 66→			return err
 67→		}
 68→
 69→		raw, err = os.ReadFile(files[1])
 70→		if err != nil {
 71→			cclog.Warn("Error while reading jobdata file for import")
 72→			return err
 73→		}
 74→
 75→		if config.Keys.Validate {
 76→			if err = schema.Validate(schema.Data, bytes.NewReader(raw)); err != nil {
 77→				return fmt.Errorf("REPOSITORY/INIT > validate job data: %v", err)
 78→			}
 79→		}
 80→		dec = json.NewDecoder(bytes.NewReader(raw))
 81→		dec.DisallowUnknownFields()
 82→		jobData := schema.JobData{}
 83→		if err = dec.Decode(&jobData); err != nil {
 84→			cclog.Warn("Error while decoding raw json jobdata for import")
 85→			return err
 86→		}
 87→
 88→		job.MonitoringStatus = schema.MonitoringStatusArchivingSuccessful
 89→
 90→		if err = enrichJobMetadata(&job); err != nil {
 91→			cclog.Errorf("Error enriching job metadata: %v", err)
 92→			return err
 93→		}
 94→
 95→		if err = SanityChecks(&job); err != nil {
 96→			cclog.Warn("BaseJob SanityChecks failed")
 97→			return err
 98→		}
 99→
100→		if err = archive.GetHandle().ImportJob(&job, &jobData); err != nil {
101→			cclog.Error("Error while importing job")
102→			return err
103→		}
104→
105→		id, err := r.InsertJobDirect(&job)
106→		if err != nil {
107→			cclog.Warn("Error while job db insert")
108→			return err
109→		}
110→
111→		for _, tag := range job.Tags {
112→			if err := r.ImportTag(id, tag.Type, tag.Name, tag.Scope); err != nil {
113→				cclog.Error("Error while adding or creating tag on import")
114→				return err
115→			}
116→		}
117→
118→		cclog.Infof("successfully imported a new job (jobId: %d, cluster: %s, dbid: %d)", job.JobID, job.Cluster, id)
119→	}
120→	return nil
121→}
