 14→// JobHook interface allows external components to hook into job lifecycle events.
 15→// Implementations can perform actions when jobs start or stop, such as tagging,
 16→// logging, notifications, or triggering external workflows.
 17→//
 18→// Example implementation:
 19→//
 20→//	type MyJobTagger struct{}
 21→//
 22→//	func (t *MyJobTagger) JobStartCallback(job *schema.Job) {
 23→//	    if job.NumNodes > 100 {
 24→//	        // Tag large jobs automatically
 25→//	    }
 26→//	}
 27→//
 28→//	func (t *MyJobTagger) JobStopCallback(job *schema.Job) {
 29→//	    if job.State == schema.JobStateFailed {
 30→//	        // Log or alert on failed jobs
 31→//	    }
 32→//	}
 33→//
 34→// Register hooks during application initialization:
 35→//
 36→//	repository.RegisterJobHook(&MyJobTagger{})
 37→type JobHook interface {
 38→	// JobStartCallback is invoked when one or more jobs start.
 39→	// This is called synchronously, so implementations should be fast.
 40→	JobStartCallback(job *schema.Job)
 41→
 42→	// JobStopCallback is invoked when a job completes.
 43→	// This is called synchronously, so implementations should be fast.
 44→	JobStopCallback(job *schema.Job)
 45→}
 46→
 47→var (
 48→	initOnce sync.Once
 49→	hooks    []JobHook
 50→)
 51→
 52→// RegisterJobHook registers a JobHook to receive job lifecycle callbacks.
 53→// Multiple hooks can be registered and will be called in registration order.
 54→// This function is safe to call multiple times and is typically called during
 55→// application initialization.
 56→//
 57→// Nil hooks are silently ignored to simplify conditional registration.
 58→func RegisterJobHook(hook JobHook) {
 59→	initOnce.Do(func() {
 60→		hooks = make([]JobHook, 0)
 61→	})
 62→
 63→	if hook != nil {
 64→		hooks = append(hooks, hook)
 65→	}
 66→}
 67→
 68→// CallJobStartHooks invokes all registered JobHook.JobStartCallback methods
 69→// for each job in the provided slice. This is called internally by the repository
 70→// when jobs are started (e.g., via StartJob or batch job imports).
 71→//
 72→// Hooks are called synchronously in registration order. If a hook panics,
 73→// the panic will propagate to the caller.
 74→func CallJobStartHooks(jobs []*schema.Job) {
 75→	if hooks == nil {
 76→		return
 77→	}
 78→
 79→	for _, hook := range hooks {
 80→		if hook != nil {
 81→			for _, job := range jobs {
 82→				hook.JobStartCallback(job)
 83→			}
 84→		}
 85→	}
 86→}
 87→
 88→// CallJobStopHooks invokes all registered JobHook.JobStopCallback methods
 89→// for the provided job. This is called internally by the repository when a
 90→// job completes (e.g., via StopJob or job state updates).
 91→//
 92→// Hooks are called synchronously in registration order. If a hook panics,
 93→// the panic will propagate to the caller.
 94→func CallJobStopHooks(job *schema.Job) {
 95→	if hooks == nil {
 96→		return
 97→	}
 98→
 99→	for _, hook := range hooks {
100→		if hook != nil {
101→			hook.JobStopCallback(job)
102→		}
103→	}
104→}
